import React, { useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Container } from 'react-bootstrap'; 
// Importaciones de Contextos
import { AuthContext } from '../context/AuthContext';
import { CartContext } from '../context/CartContext';
import { SettingsContext } from '../context/SettingsContext'; 
// Componentes dependientes
import HeaderSkeleton from './HeaderSkeleton'; 
import styles from './Header.module.css'; // Importamos el CSS Module

const Header = () => {
  const navigate = useNavigate();
  // Renombramos loading para evitar conflictos
  const { userInfo: user, logout, loading: authLoading } = useContext(AuthContext); 
  const { cartItems, isItemJustAdded } = useContext(CartContext);
  const { settings, loading: settingsLoading } = useContext(SettingsContext);

  useEffect(() => {
    // Aplicar el color de acento de la configuración a las variables CSS globales
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  const isLoading = authLoading || settingsLoading;

  if (isLoading) {
     return <HeaderSkeleton />;
  }
  
  // --- LÓGICA CRÍTICA DEL ACENTO ---
  const siteName = (settings?.siteName || 'TECNOTITLÁN').toUpperCase(); // Aseguramos mayúsculas
  
  // Reemplazamos 'Á' por el span de acento verde
  const accentedName = siteName.replace(/Á/g, `<span class="${styles.accent}">Á</span>`);
  
  return (
    // Aplicamos la clase base del CSS Module
    <header 
      className={`w-full sticky top-0 z-50 transition-all duration-300 shadow-md ${styles.header}`}
    >
      {/* CRÍTICO: Quitamos el padding vertical para que el CSS Module controle la altura */}
      <Container> 
        {/* CRÍTICO: d-flex para la alineación horizontal de Logo y espacio para otros elementos */}
        <div className="d-flex justify-content-between align-items-center h-full"> 
          
          {/* 1. Logo / Nombre del Sitio (Aplicamos la clase CSS Module) */}
          <Link 
            to="/" 
            // CRÍTICO: Solo usamos la clase del CSS Module.
            className={`${styles.logoText} d-flex align-items-center gap-2 flex-shrink-0`} 
          > 
            {/* NO hay imagen, solo texto para debugging */}
            
            {/* Contenedor del Texto (stack vertical) */}
            <div className="flex flex-col items-start">
                <span dangerouslySetInnerHTML={{ __html: accentedName }}>
                  {/* Se renderiza el HTML inyectado para el acento */}
                </span>
                <span>
                  Tecnología con Raíces
                </span>
            </div>
          </Link>

          {/* 2. ESPACIO CENTRAL: Aquí irá el SearchBox (Desktop) */}
          {/* El div flex-grow asegura que este espacio ocupe todo el centro */}
          <div className="flex-grow"></div> 

          {/* 3. ESPACIO DERECHO: Aquí irán Carrito y Usuario */}
          {/* Dejamos un div vacío para mantener el espaciado y simetría. */}
          <div className="w-auto flex-shrink-0">
             {/* Aquí se reintroducirán los botones de navegación */}
          </div>
        </div>
        
        {/* NO hay SearchBox móvil aún */}
      </Container>
    </header>
  );
};

export default Header;
